const data = msg.payload;

// Vérifier la validité de la réponse
if (!data || !data.main || !data.wind) {
    node.error('OpenWeatherMap: réponse invalide — ' + JSON.stringify(data), msg);
    node.status({fill: 'red', shape: 'ring', text: 'Réponse invalide'});
    return null;
}

if (data.cod && data.cod !== 200) {
    node.error('OpenWeatherMap erreur ' + data.cod + ': ' + (data.message || ''), msg);
    node.status({fill: 'red', shape: 'dot', text: 'Erreur ' + data.cod});
    return null;
}

// === Extraction des valeurs ===
const extTemp   = data.main.temp;         // °C
const humidity  = data.main.humidity;     // %
const pressKpa  = data.main.pressure / 10.0; // hPa → kPa
const windSpeed = data.wind.speed  || 0;  // m/s
const windDir   = data.wind.deg    || 0;  // degrés 0-360

// Stocker dans contexte global pour le keepalive (25s)
global.set('owm_ext_temp',   extTemp);
global.set('owm_humidity',   humidity);
global.set('owm_press_kpa',  pressKpa);
global.set('owm_wind_speed', windSpeed);
global.set('owm_wind_dir',   windDir);

node.status({
    fill: 'green', shape: 'dot',
    text: `${extTemp.toFixed(1)}°C · ${humidity}% · ${windSpeed}m/s · ${windDir}°`
});

// === Message 1 : com.victronenergy.meteo (instance 40) ===
const meteoMsg = {
    topic: 'santuario/meteo/venus',
    payload: JSON.stringify({
        ExternalTemperature: extTemp,
        WindDirection:       windDir,
        WindSpeed:           windSpeed
    })
};

// === Message 2 : com.victronenergy.temperature.mqtt_1 (instance 20) ===
const heatMsg = {
    topic: 'santuario/heat/1/venus',
    payload: JSON.stringify({
        Temperature:     extTemp,
        TemperatureType: 4,
        Status:          0,
        Humidity:        humidity,
        Pressure:        pressKpa,
        CustomName:      'Météo Extérieure',
        ProductName:     'OpenWeatherMap'
    })
};

return [meteoMsg, heatMsg];

const extTemp   = global.get('owm_ext_temp');
const humidity  = global.get('owm_humidity');
const pressKpa  = global.get('owm_press_kpa');
const windSpeed = global.get('owm_wind_speed');
const windDir   = global.get('owm_wind_dir');

// Attendre la première récupération OpenWeatherMap
if (extTemp === undefined || extTemp === null) {
    return null;
}

const meteoMsg = {
    topic: 'santuario/meteo/venus',
    payload: JSON.stringify({
        ExternalTemperature: extTemp,
        WindDirection:       windDir  || 0,
        WindSpeed:           windSpeed || 0
    })
};

const heatMsg = {
    topic: 'santuario/heat/1/venus',
    payload: JSON.stringify({
        Temperature:     extTemp,
        TemperatureType: 4,
        Status:          0,
        Humidity:        humidity  || 0,
        Pressure:        pressKpa  || 0,
        CustomName:      'Météo Extérieure',
        ProductName:     'OpenWeatherMap'
    })
};

return [meteoMsg, heatMsg];
